/* --------------------------------- PHOTOS --------------------------------- */

function getCurrentGeoQuick(timeoutMs){
  return new Promise((resolve)=>{
    if(!navigator.geolocation){ resolve(null); return; }
    let done = false;
    const timer = setTimeout(()=>{ if(!done){ done=true; resolve(null); } }, timeoutMs || 6000);
    navigator.geolocation.getCurrentPosition(pos=>{
      if(done) return; done = true; clearTimeout(timer);
      resolve({ lat: pos.coords.latitude, lon: pos.coords.longitude, accuracy: pos.coords.accuracy });
    }, ()=>{
      if(done) return; done = true; clearTimeout(timer);
      resolve(null);
    }, { enableHighAccuracy:true, timeout: timeoutMs || 6000, maximumAge: 30000 });
  });
}

function drawStamp(ctx, w, h, geo){
  const now = new Date();
  const dayNames = ['MINGGU','SENIN','SELASA','RABU','KAMIS','JUMAT','SABTU'];
  const monNames = ['JAN','FEB','MAR','APR','MEI','JUN','JUL','AGU','SEP','OKT','NOV','DES'];
  const dateStr = `${dayNames[now.getDay()]}, ${String(now.getDate()).padStart(2,'0')} ${monNames[now.getMonth()]} ${now.getFullYear()}`;
  const timeStr = `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  let coordStr = null;
  if(geo && geo.lat!=null && geo.lon!=null){
    coordStr = `${geo.lat.toFixed(6)}, ${geo.lon.toFixed(6)}` + (geo.accuracy ? `  (±${Math.round(geo.accuracy)}m)` : '');
  }

  const barH = Math.max(52, Math.round(h*0.13));
  const grad = ctx.createLinearGradient(0, h-barH, 0, h);
  grad.addColorStop(0, 'rgba(0,0,0,0)');
  grad.addColorStop(1, 'rgba(0,0,0,0.62)');
  ctx.fillStyle = grad;
  ctx.fillRect(0, h-barH, w, barH);

  const fontSize = Math.max(13, Math.round(w*0.028));
  ctx.textBaseline = 'bottom';
  ctx.textAlign = 'right';
  ctx.shadowColor = 'rgba(0,0,0,0.6)';
  ctx.shadowBlur = 3;
  ctx.fillStyle = '#ffffff';

  let y = h - Math.round(fontSize*0.6);
  if(coordStr){
    ctx.font = `600 ${fontSize}px Arial, sans-serif`;
    ctx.fillText(coordStr, w - 12, y);
    y -= Math.round(fontSize*1.35);
  }
  ctx.font = `700 ${Math.round(fontSize*1.05)}px Arial, sans-serif`;
  ctx.fillText(`${dateStr}  •  ${timeStr}`, w - 12, y);

  // pin icon bottom-left
  ctx.textAlign = 'left';
  ctx.font = `${Math.round(fontSize*1.6)}px Arial, sans-serif`;
  ctx.fillText('📍', 10, h - Math.round(fontSize*0.55));
  ctx.shadowBlur = 0;
}

function compressImage(file, maxDim, quality, stampGeo){
  return new Promise((resolve, reject)=>{
    const img = new Image();
    const reader = new FileReader();
    reader.onload = ()=>{ img.src = reader.result; };
    reader.onerror = reject;
    img.onload = ()=>{
      let { width, height } = img;
      if(width > height && width > maxDim){ height = Math.round(height*maxDim/width); width = maxDim; }
      else if(height > maxDim){ width = Math.round(width*maxDim/height); height = maxDim; }
      const canvas = document.createElement('canvas');
      canvas.width = width; canvas.height = height;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, width, height);
      if(stampGeo !== false){
        drawStamp(ctx, width, height, stampGeo);
      }
      canvas.toBlob(blob=>{
        const fr = new FileReader();
        fr.onload = ()=> resolve({ blob, dataUrl: fr.result, width, height });
        fr.onerror = reject;
        fr.readAsDataURL(blob);
      }, 'image/jpeg', quality || 0.72);
    };
    img.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function photoSlotEl(key, label){
  const inputCamId = 'photocam_'+key;
  const inputGalId = 'photogal_'+key;
  const preview = el('div',{class:'photo-preview', id:'prev_'+key}, 'Belum ada foto');
  const slot = el('div',{class:'photo-slot', id:'slot_'+key});

  async function handleFile(file){
    if(!file) return;
    preview.textContent = state.stampEnabled ? 'Mengambil lokasi & memproses...' : 'Memproses...';
    try{
      let geo = null;
      if(state.stampEnabled){
        geo = await getCurrentGeoQuick(6000);
        if(!geo && state.fields.koordinat){
          const parts = state.fields.koordinat.split(',').map(s=>parseFloat(s.trim()));
          if(parts.length===2 && !isNaN(parts[0]) && !isNaN(parts[1])) geo = { lat:parts[0], lon:parts[1] };
        }
      }
      const { blob, dataUrl, width, height } = await compressImage(file, 1400, 0.72, state.stampEnabled ? geo : false);
      state.photos[key] = { blob, dataUrl, width, height, name: key+'.jpg' };
      preview.innerHTML = '';
      preview.appendChild(el('img',{src:dataUrl}));
      slot.classList.add('filled');
    }catch(err){
      preview.textContent = 'Gagal memuat foto';
    }
  }

  slot.appendChild(el('div',{class:'ps-label'}, label));
  slot.appendChild(preview);
  slot.appendChild(el('div',{class:'photo-actions'},
    el('label',{class:'upl', for:inputCamId}, '📷 Kamera'),
    el('input',{type:'file', id:inputCamId, accept:'image/*', capture:'environment',
      onchange: e=> handleFile(e.target.files[0])}),
    el('label',{class:'upl', for:inputGalId, style:'background:var(--accent-2);'}, '🖼️ Galeri / File'),
    el('input',{type:'file', id:inputGalId, accept:'image/*',
      onchange: e=> handleFile(e.target.files[0])}),
    el('button',{type:'button', class:'clear-btn', onclick:()=>{
      delete state.photos[key];
      preview.innerHTML = ''; preview.textContent = 'Belum ada foto';
      slot.classList.remove('filled');
      document.getElementById(inputCamId).value = '';
      document.getElementById(inputGalId).value = '';
    }}, '✕')
  ));
  slot.appendChild(el('p',{class:'hint', style:'margin-top:6px;'},
    'Pakai app kamera timestamp? Motret dulu di app itu, lalu tekan "Galeri / File" untuk memilihnya di sini.'));
  return slot;
}

