/* --------------------------- LOCATION AUTOCOMPLETE ------------------------- */

function searchLocations(query){
  const q = (query||'').trim().toLowerCase();
  if(q.length < 2) return [];
  const words = q.split(/\s+/).filter(Boolean);
  const scored = [];
  for(const loc of LOCATION_DB){
    const hay = ((loc.nama||'')+' '+(loc.id||'')+' '+(loc.kabupaten||'')+' '+(loc.alamat||'')).toLowerCase();
    if(words.every(w=> hay.includes(w))){
      const startsWithBonus = (loc.nama||'').toLowerCase().startsWith(q) ? 0 : 1;
      scored.push([startsWithBonus, loc]);
    }
    if(scored.length >= 400) break;
  }
  scored.sort((a,b)=> a[0]-b[0]);
  return scored.slice(0,8).map(x=>x[1]);
}

function locationAutocompleteField(){
  state.fields['nama_lokasi'] = state.fields['nama_lokasi'] || '';
  const wrap = el('div',{style:'position:relative;'});
  const input = el('input',{type:'text', id:'f_nama_lokasi', value:state.fields['nama_lokasi'],
    placeholder:'Ketik nama lokasi... (contoh: kantor desa mangunjaya)', autocomplete:'off'});
  const dropdown = el('div',{style:'position:absolute;left:0;right:0;top:100%;background:#fff;border:1px solid var(--border);border-radius:8px;margin-top:4px;max-height:260px;overflow:auto;z-index:30;box-shadow:0 6px 18px rgba(15,41,66,.12);display:none;'});

  function closeDropdown(){ dropdown.style.display = 'none'; dropdown.innerHTML=''; }

  function applyLocation(loc){
    state.fields['nama_lokasi'] = loc.nama || '';
    state.fields['site_id'] = loc.id || '';
    state.fields['provinsi'] = loc.provinsi || '';
    state.fields['kabupaten'] = loc.kabupaten || '';
    state.fields['alamat'] = loc.alamat || '';
    if(loc.lat!=null && loc.lon!=null) state.fields['koordinat'] = loc.lat+', '+loc.lon;
    input.value = state.fields['nama_lokasi'];
    ['site_id','provinsi','kabupaten','alamat','koordinat'].forEach(id=>{
      const elx = document.getElementById('f_'+id);
      if(elx) elx.value = state.fields[id];
    });
    closeDropdown();
  }

  input.addEventListener('input', e=>{
    state.fields['nama_lokasi'] = e.target.value;
    const results = searchLocations(e.target.value);
    if(!results.length){ closeDropdown(); return; }
    dropdown.innerHTML = '';
    results.forEach(loc=>{
      const item = el('div',{style:'padding:9px 12px;cursor:pointer;border-bottom:1px solid #f0f2f5;font-size:.85rem;'},
        el('div',{style:'font-weight:600;color:var(--navy);'}, loc.nama || '(tanpa nama)'),
        el('div',{style:'color:var(--muted);font-size:.75rem;margin-top:2px;'}, [loc.kabupaten, loc.provinsi].filter(Boolean).join(' — '))
      );
      item.addEventListener('mousedown', (ev)=>{ ev.preventDefault(); applyLocation(loc); });
      dropdown.appendChild(item);
    });
    dropdown.style.display = 'block';
  });
  input.addEventListener('blur', ()=> setTimeout(closeDropdown, 150));
  input.addEventListener('focus', e=>{ if(e.target.value.trim().length>=2) input.dispatchEvent(new Event('input')); });

  wrap.appendChild(el('label',{for:'f_nama_lokasi'}, 'Nama Lokasi', el('span',{class:'opt'},' (ketik untuk cari dari database 643 site)')));
  wrap.appendChild(input);
  wrap.appendChild(dropdown);
  wrap.appendChild(el('p',{class:'hint'}, 'Kalau lokasi ketemu di daftar, pilih untuk auto-isi Site ID, Provinsi, Kabupaten & Alamat. Kalau tidak ketemu, ketik manual saja lalu lengkapi field lain sendiri.'));
  return wrap;
}

